from dataclasses import dataclass
from enum import Enum

class FeedbackCategory(str, Enum):
    RESPONSE_QUALITY     = "response_quality"    # output was not what was needed
    RESPONSE_FORMAT      = "response_format"     # output was right but poorly formatted
    FACTUAL_ACCURACY     = "factual_accuracy"    # output was factually incorrect
    SAFETY_CONCERN       = "safety_concern"      # output raised a safety issue
    TOOL_USE_FAILURE     = "tool_use_failure"    # tool call produced wrong result
    LATENCY              = "latency"             # response took too long
    IRRELEVANT_RESPONSE  = "irrelevant_response" # response did not address the query
    POSITIVE             = "positive"            # explicitly positive feedback

@dataclass
class ClassifiedFeedback:
    record: "FeedbackRecord"
    category: FeedbackCategory
    confidence: float           # 0.0 to 1.0
    routing_queue: str          # "safety", "quality", "format", "metrics-only"
    priority: int               # 1 = highest, 5 = lowest
    classification_method: str  # "keyword_rule" | "ml_classifier" | "human_review"

    def should_skip_automated_processing(self) -> bool:
        return (
            self.category == FeedbackCategory.SAFETY_CONCERN
            or self.record.channel == "support_ticket"
        )

def classify_feedback(record: "FeedbackRecord") -> ClassifiedFeedback:
    comment = (record.free_text_comment or "").lower()
    # Safety: highest priority, always human-routed
    if any(w in comment for w in ["harmful", "offensive", "dangerous", "wrong fact"]):
        return ClassifiedFeedback(
            record=record, category=FeedbackCategory.SAFETY_CONCERN,
            confidence=0.9, routing_queue="safety", priority=1,
            classification_method="keyword_rule",
        )
    # Factual accuracy signals
    if any(w in comment for w in ["incorrect", "wrong", "inaccurate", "false"]):
        return ClassifiedFeedback(
            record=record, category=FeedbackCategory.FACTUAL_ACCURACY,
            confidence=0.75, routing_queue="quality", priority=2,
            classification_method="keyword_rule",
        )
    # Format issues
    if any(w in comment for w in ["format", "layout", "markdown", "table", "spacing"]):
        return ClassifiedFeedback(
            record=record, category=FeedbackCategory.RESPONSE_FORMAT,
            confidence=0.8, routing_queue="quality", priority=4,
            classification_method="keyword_rule",
        )
    # Default: implicit negative sentiment, lowest priority
    return ClassifiedFeedback(
        record=record, category=FeedbackCategory.RESPONSE_QUALITY,
        confidence=0.5, routing_queue="metrics-only", priority=5,
        classification_method="keyword_rule",
    )
